commits.content:
    /* Section Title */
    .section-title {
      font-weight: bold;
      margin-bottom: 20px;
    }

    /* Cards */
    .card:hover {
      transform: translateY(-5px);
      transition: 0.3s;
    }

    /* Glass Card - Side by Side Layout */
    .glass-card {
      display: flex;
      flex-wrap: wrap;
      gap: 2rem;
      align-items: flex-start;
      /* background: linear-gradient(135deg, rgba(255, 255, 255, 0.95) 0%, rgba(248, 250, 252, 0.95) 100%); */
      backdrop-filter: blur(10px);
      /* border: 1px solid rgba(0, 180, 216, 0.1);
      border-radius: 20px;
      box-shadow: 0 15px 40px rgba(0, 0, 0, 0.08); */
      transition: all 0.3s ease;
    }

    .glass-card:hover {
      box-shadow: 0 20px 50px rgba(0, 0, 0, 0.12);
      border-color: rgba(0, 180, 216, 0.2);
    }

    .glass-card > .row {
      flex: 1 1 50%;
      min-width: 300px;
      width: 100%;
    }

    /* Content Title - History Section */
    .content-title {
      font-size: 28px;
      font-weight: 700;
      color: #1e3a5f;
      margin-bottom: 30px !important;
      position: relative;
      display: inline-block;
      padding-bottom: 15px;
    }

    .content-title::after {
      content: '';
      position: absolute;
      bottom: 0;
      left: 0;
      width: 60px;
      height: 4px;
      background: linear-gradient(90deg, #00b4d8, #f0a500);
      border-radius: 2px;
    }

    /* Responsive: Stack on smaller screens */
    @media (max-width: 968px) {
      .glass-card {
        flex-direction: column;
      }

      .glass-card .left-overview {
        flex: 1 1 100%;
      }

      .glass-card > .row {
        flex: 1 1 100%;
      }
    }

    @media (max-width: 768px) {
      .glass-card {
        flex-direction: column;
        padding: 20px !important;
      }

      .glass-card .left-overview {
        flex: 1 1 100%;
      }

      .glass-card > .row {
        flex: 1 1 100%;
      }

      .content-title {
        font-size: 24px;
      }
    }

    /* ===== LEFT & RIGHT HISTORY LAYOUT ===== */
    .glass-card .left-history,
    .glass-card .right-history {
      display: flex;
      flex-direction: column;
      justify-content: flex-start;
      align-items: stretch;
    }

    /* Left History - Text Content */
    .glass-card .left-history {
      flex: 1 1 45%;
      min-width: 280px;
      padding-right: 20px;
    }

    /* Right History - Timeline */
    .glass-card .right-history {
      flex: 1 1 50%;
      min-width: 280px;
      padding-left: 20px;
      border-left: 2px solid rgba(0, 180, 216, 0.2);
    }

    /* Responsive: Stack on smaller screens */
    @media (max-width: 992px) {
      .glass-card .left-history,
      .glass-card .right-history {
        flex: 1 1 100%;
        padding-right: 0;
        padding-left: 0;
        border-left: none;
        margin-bottom: 30px;
      }

      .glass-card .right-history {
        margin-bottom: 0;
      }
    }

    @media (max-width: 768px) {
      .glass-card .left-history,
      .glass-card .right-history {
        flex: 1 1 100%;
        padding: 0;
        margin-bottom: 20px;
      }

      .glass-card .right-history {
        margin-bottom: 0;
      }
    }

    /* ===== STAT CARDS STYLING ===== */
    .stat-card {
      position: relative;
      background: linear-gradient(135deg, #ffffff 0%, #f8fafc 100%);
      border: 1px solid rgba(0, 180, 216, 0.1);
      border-radius: 15px;
      transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
      overflow: hidden;
      box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      text-align: center;
      padding: 35px 25px !important;
    }

    /* Stat Card Icon Container */
    .stat-card i {
      transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
      filter: drop-shadow(0 4px 12px rgba(30, 58, 95, 0.1));
    }

    /* Stat Card Hover Effects */
    .stat-card:hover {
      transform: translateY(-15px);
      box-shadow: 0 25px 50px rgba(0, 0, 0, 0.15);
      border-color: rgba(0, 180, 216, 0.3);
    }

    .stat-card:hover i {
      transform: scale(1.25) rotateY(10deg);
    }

    /* Stat Card Title */
    .stat-card h4 {
      font-size: 22px;
      font-weight: 700;
      margin: 15px 0 10px 0 !important;
      letter-spacing: -0.3px;
      position: relative;
      z-index: 2;
    }

    .stat-card h4.text-primary {
      color: #1e3a5f !important;
    }

    .stat-card h4.text-success {
      color: #28a745 !important;
    }

    .stat-card h4.text-info {
      color: #17a2b8 !important;
    }

    /* Stat Card Description */
    .stat-card p {
      font-size: 14px;
      color: #6b7b8d;
      margin: 0 !important;
      line-height: 1.6;
      position: relative;
      z-index: 2;
    }

    /* Stat Card Background Animation */
    .stat-card::before {
      content: '';
      position: absolute;
      top: -100%;
      left: 0;
      width: 100%;
      height: 100%;
      background: linear-gradient(135deg, rgba(0, 180, 216, 0.05), rgba(240, 165, 0, 0.05));
      transition: top 0.5s cubic-bezier(0.4, 0, 0.2, 1);
      z-index: 1;
    }

    .stat-card:hover::before {
      top: 0;
    }

    /* Responsive Stat Cards */
    @media (max-width: 992px) {
      .stat-card {
        padding: 30px 20px !important;
      }

      .stat-card h4 {
        font-size: 20px;
      }
    }

    @media (max-width: 768px) {
      .stat-card {
        padding: 25px 18px !important;
      }

      .stat-card h4 {
        font-size: 18px;
      }

      .stat-card p {
        font-size: 13px;
      }
    }
.top-tab {
    padding: 12px 24px;
    border: none;
    background: none;
    font-weight: 600;
    font-size: 1rem;
    cursor: pointer;
    position: relative;
    color: var(--text-dark);
    transition: all 0.3s ease;
}

.top-tab::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 0;
    height: 3px;
    background: linear-gradient(90deg, var(--accent), var(--gold));
    transition: width 0.3s ease;
}

.top-tab:hover::after,
.top-tab.active::after {
    width: 100%;
}

.top-tab:hover {
    color: var(--primary);
}

.top-tab.active {
    color: var(--primary);
}

/* Tabs */
.tab-content-custom {
    display: none;
}

.tab-content-custom.active {
    display: block;
    animation: fadeIn 0.5s ease;
}

@keyframes fadeIn {
    from {opacity:0; transform: translateY(20px);}
    to {opacity:1; transform: translateY(0);}
}


