/* ===== TIMELINE MODERN STYLING ===== */
.timeline-modern {
    position: relative;
    padding: 30px 0;
}

/* Vertical connecting line */
.timeline-modern::before {
    content: '';
    position: absolute;
    left: 30px;
    top: 0;
    bottom: 0;
    width: 3px;
    background: linear-gradient(180deg, #00b4d8 0%, #f0a500 100%);
    border-radius: 2px;
}

/* Timeline Items */
.timeline-item {
    position: relative;
    margin-bottom: 40px;
    padding-left: 100px;
    animation: timelineItemFade 0.6s ease-out forwards;
    opacity: 0;
}

.timeline-item:nth-child(1) { animation-delay: 0.1s; }
.timeline-item:nth-child(2) { animation-delay: 0.3s; }
.timeline-item:nth-child(3) { animation-delay: 0.5s; }

@keyframes timelineItemFade {
    from {
        opacity: 0;
        transform: translateX(-20px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

/* Timeline Icon Circle */
.timeline-icon {
    position: absolute;
    left: -5px;
    top: 5px;
    width: 70px;
    height: 70px;
    background: linear-gradient(135deg, #00b4d8 0%, #0099bb 100%);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: white;
    font-size: 28px;
    box-shadow: 0 8px 25px rgba(0, 180, 216, 0.3);
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    border: 4px solid white;
}

.timeline-item:hover .timeline-icon {
    transform: scale(1.15) translateY(-8px);
    box-shadow: 0 12px 35px rgba(0, 180, 216, 0.5);
    background: linear-gradient(135deg, #f0a500 0%, #ffc947 100%);
}

/* Timeline Content Card */
.timeline-content {
    background: linear-gradient(135deg, #ffffff 0%, #f8fafc 100%);
    padding: 25px 28px;
    border-radius: 15px;
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.08);
    border: 1px solid rgba(0, 180, 216, 0.1);
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    position: relative;
    overflow: hidden;
}

/* Gradient overlay on hover */
.timeline-content::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(0, 180, 216, 0.1), transparent);
    transition: left 0.5s ease;
}

.timeline-item:hover .timeline-content {
    transform: translateY(-6px);
    box-shadow: 0 12px 30px rgba(0, 0, 0, 0.12);
    border-color: rgba(0, 180, 216, 0.3);
}

.timeline-item:hover .timeline-content::before {
    left: 100%;
}

/* Timeline Content Typography */
.timeline-content h5 {
    font-size: 18px;
    font-weight: 700;
    color: #1e3a5f;
    margin-bottom: 10px;
    letter-spacing: -0.3px;
}

.timeline-content p {
    font-size: 14px;
    color: #6b7b8d;
    line-height: 1.6;
    margin: 0;
}

/* ===== HISTORY 2-COLUMN LAYOUT ===== */
.glass-card .left-history,
.glass-card .right-history {
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
