}


/* ===== CORE VALUES CARDS STYLING ===== */
.value-card-modern {
    position: relative;
    background: linear-gradient(135deg, #ffffff 0%, #f8fafc 100%);
    border: 1px solid rgba(0, 180, 216, 0.1) !important;
    border-radius: 18px !important;
    transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
    overflow: hidden;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

/* Value Icon Container */
.value-card-modern .value-icon {
    width: 80px;
    height: 80px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    margin-bottom: 20px !important;
    position: relative;
    z-index: 2;
    transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
    background: linear-gradient(135deg, rgba(0, 180, 216, 0.1), rgba(240, 165, 0, 0.05));
    border: 2px solid rgba(0, 180, 216, 0.2);
}

.value-card-modern i {
    transition: all 0.4s ease;
    filter: drop-shadow(0 4px 12px rgba(30, 58, 95, 0.1));
}

/* Value Card Hover Effects */
.value-card-modern:hover {
    transform: translateY(-15px) rotateX(5deg);
    box-shadow: 0 25px 50px rgba(0, 0, 0, 0.15);
    border-color: rgba(0, 180, 216, 0.3) !important;
}

.value-card-modern:hover .value-icon {
    background: linear-gradient(135deg, #00b4d8, #0099bb);
    border-color: transparent;
    box-shadow: 0 12px 30px rgba(0, 180, 216, 0.3);
}

.value-card-modern:hover i {
    color: white !important;
    transform: scale(1.2) rotateZ(360deg);
}

/* Value Card Title */
.value-card-modern h6 {
    font-size: 16px;
    color: #1e3a5f;
    letter-spacing: -0.3px;
    position: relative;
    z-index: 2;
    margin-bottom: 12px !important;
    text-transform: uppercase;
    font-weight: 700;
}

/* Value Card Description */
.value-card-modern p {
    font-size: 13px;
    color: #6b7b8d;
    line-height: 1.6;
    position: relative;
    z-index: 2;
    margin: 0;
}

/* Value Card Background Animation */
.value-card-modern::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -50%;
    width: 100%;
    height: 100%;
    background: radial-gradient(circle, rgba(0, 180, 216, 0.1) 0%, transparent 70%);
    transition: all 0.6s ease;
    z-index: 1;
}

.value-card-modern:hover::before {
    top: -25%;
    right: -25%;
}

/* Preserve Hover Lift Class */
.hover-lift {
    position: relative;
}

.hover-lift::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 0;
    height: 4px;
    background: linear-gradient(90deg, #00b4d8, #f0a500);
    transition: width 0.4s ease;
    z-index: 2;
}

.value-card-modern:hover::after {
    width: 100%;
}

/* Responsive Value Cards */
@media (max-width: 992px) {
    .value-card-modern {
        min-height: 280px;
    }
}

@media (max-width: 768px) {
    .value-card-modern {
        padding: 30px 20px !important;
    }

    .value-icon {
        width: 70px !important;
        height: 70px !important;
    }

    .value-card-modern h6 {
        font-size: 14px;
    }

    .value-card-modern p {
        font-size: 12px;
    }
}
